import { execution } from '@dynatrace-sdk/automation-utils';
import { eventsClient, EventIngestEventType } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    const eventType = input.eventType?.toUpperCase() || 'CUSTOM_INFO';
    const properties = {};

    if (input.eventProperties) {
      const customProps = typeof input.eventProperties === 'string' ? JSON.parse(input.eventProperties) : input.eventProperties;
      Object.assign(properties, customProps);
    }

    const event = {
      eventType: eventType === 'CUSTOM_ALERT' ? EventIngestEventType.CustomAlert : EventIngestEventType.CustomInfo,
      title: input.eventTitle,
      properties: properties
    };

    const result = await eventsClient.createEvent({
      body: event
    });

    console.log(`Custom event created: ${result.eventIngestResults[0].correlationId}`);

    return {
      correlationId: result.eventIngestResults[0].correlationId,
      eventType: eventType,
      title: input.eventTitle,
      timestamp: new Date().toISOString(),
      success: true
    };
  } catch (error) {
    console.error('Error creating event:', error);
    throw new Error(`Failed to create event: ${error}`);
  }
}
